#!/usr/bin/env python3
import argparse
from pathlib import Path

TEMPLATE = """
// AUTO-GENERATED by gen_microbench.py

target C {{
  files: ["{lib_path}"]
}}

preamble {{=
#include <stdlib.h>
#include "ms_eval_log.h"
#include "core/reactor.h"

static int ms_eval_inject_period = 0;
static int ms_eval_inject_rate = 0;
static int ms_eval_inject_delay_us = 0;
static int ms_eval_deadline_us = {deadline_us};
static int ms_eval_steps = {steps};
static int ms_eval_workload_us = {workload_us};
static int ms_eval_seed = {seed};

static int ms_eval_get_env_int(const char* key, int fallback) {{
  const char* v = getenv(key);
  return v ? atoi(v) : fallback;
}}
=}}

main reactor Microbench {{
  timer t(0, {period_us} us);
  state int step = 0;

  reaction(startup) {{=
    ms_eval_inject_period = ms_eval_get_env_int("MS_EVAL_INJECT_PERIOD", 0);
    ms_eval_inject_rate = ms_eval_get_env_int("MS_EVAL_INJECT_RATE_PCT", 0);
    ms_eval_inject_delay_us = ms_eval_get_env_int("MS_EVAL_INJECT_DELAY_US", 0);
    const char* log_path = getenv("LF_APP_LOG");
    const char* mode = getenv("MS_MODE");
    ms_eval_log_init(log_path, "{experiment}", mode, {reactions}, ms_eval_steps,
                     ms_eval_workload_us, ms_eval_deadline_us, 1.0, ms_eval_seed);
  =}}

{reactions_block}
}}
"""

REACTION_TEMPLATE = """
  reaction(t) {{=
    const int reaction_id = {rid};
    int64_t logical = (int64_t)lf_time_logical();
    int64_t physical = (int64_t)lf_time_physical();
    int inject = ms_eval_should_inject(reaction_id, logical,
                                       ms_eval_inject_period, ms_eval_inject_rate);
    if (inject) {{
      ms_eval_log_injection(reaction_id, logical, ms_eval_inject_delay_us,
                            ms_eval_deadline_us, (ms_eval_inject_delay_us > ms_eval_deadline_us));
    }}
    ms_eval_log_reaction_start(reaction_id, logical, physical);
    ms_eval_busy_wait_us(ms_eval_workload_us + (inject ? ms_eval_inject_delay_us : 0));
    int64_t physical_end = (int64_t)lf_time_physical();
    int missed = (ms_eval_deadline_us > 0 &&
                  physical_end > logical + (int64_t)ms_eval_deadline_us * 1000LL);
    ms_eval_log_reaction_end(reaction_id, logical, physical_end, ms_eval_deadline_us, missed);
    {step_logic}
  =}}
"""


def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument("--out", required=True)
    ap.add_argument("--reactions", type=int, required=True)
    ap.add_argument("--workload-us", type=int, required=True)
    ap.add_argument("--deadline-us", type=int, required=True)
    ap.add_argument("--period-us", type=int, default=1000)
    ap.add_argument("--steps", type=int, default=1000)
    ap.add_argument("--seed", type=int, default=1)
    ap.add_argument("--experiment", default="e1")
    ap.add_argument("--lib-path", default="../lf-templates/lib/ms_eval_log.c")
    args = ap.parse_args()

    reactions = []
    for rid in range(args.reactions):
        step_logic = ""
        if rid == 0:
            step_logic = "step++; if (step >= ms_eval_steps) lf_request_stop();"
        reactions.append(REACTION_TEMPLATE.format(rid=rid, step_logic=step_logic))

    out_path = Path(args.out)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(
        TEMPLATE.format(
            lib_path=args.lib_path,
            reactions=args.reactions,
            steps=args.steps,
            workload_us=args.workload_us,
            deadline_us=args.deadline_us,
            period_us=args.period_us,
            seed=args.seed,
            experiment=args.experiment,
            reactions_block="\n".join(reactions),
        )
    )


if __name__ == "__main__":
    main()
